import{_ as l,o as a,c as r,a2 as i}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"🔍 玻璃基板研究 — 已發現的問題與缺口","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/玻璃基板研究/玻璃基板問題清單_2026-05-05.md","filePath":"Deep32Q知識庫/產業洞察/玻璃基板研究/玻璃基板問題清單_2026-05-05.md"}'),o={name:"Deep32Q知識庫/產業洞察/玻璃基板研究/玻璃基板問題清單_2026-05-05.md"};function e(s,t,n,h,d,g){return a(),r("div",null,[...t[0]||(t[0]=[i('<h1 id="🔍-玻璃基板研究-—-已發現的問題與缺口" tabindex="-1">🔍 玻璃基板研究 — 已發現的問題與缺口 <a class="header-anchor" href="#🔍-玻璃基板研究-—-已發現的問題與缺口" aria-label="Permalink to &quot;🔍 玻璃基板研究 — 已發現的問題與缺口&quot;">​</a></h1><p><strong>分析日期</strong>：2026-05-05 <strong>研究範圍</strong>：玻璃基板三份報告（產業總覽、台股供應鏈、技術路線圖）的問題檢視</p><hr><h2 id="🔴-問題一-悅城-6405-已轉型-資料可能過時" tabindex="-1">🔴 問題一：悅城（6405）已轉型，資料可能過時 <a class="header-anchor" href="#🔴-問題一-悅城-6405-已轉型-資料可能過時" aria-label="Permalink to &quot;🔴 問題一：悅城（6405）已轉型，資料可能過時&quot;">​</a></h2><ul><li>2025 年已淡出玻璃基板業務，轉型做氮化鋁陶瓷</li><li>原始 drop 任務仍把它列為概念股，需要標註「不推薦」</li><li><strong>已處理</strong>：在台股供應鏈報告中標記為 🔴 不推薦</li></ul><hr><h2 id="🔴-問題二-部分營收貢獻度是「估算」-非實際數據" tabindex="-1">🔴 問題二：部分營收貢獻度是「估算」，非實際數據 <a class="header-anchor" href="#🔴-問題二-部分營收貢獻度是「估算」-非實際數據" aria-label="Permalink to &quot;🔴 問題二：部分營收貢獻度是「估算」，非實際數據&quot;">​</a></h2><ul><li>各廠玻璃基板相關營收佔比（3-40%）都是<strong>預估值</strong></li><li>目前多數廠商尚未量產，實際營收貢獻極低或為零</li><li><strong>風險</strong>：投資人可能誤以為這些公司已有實質營收</li></ul><hr><h2 id="🔴-問題三-t-glass-日東紡-壟斷風險未解決" tabindex="-1">🔴 問題三：T-Glass（日東紡）壟斷風險未解決 <a class="header-anchor" href="#🔴-問題三-t-glass-日東紡-壟斷風險未解決" aria-label="Permalink to &quot;🔴 問題三：T-Glass（日東紡）壟斷風險未解決&quot;">​</a></h2><ul><li>日東紡佔全球 T-Glass 約 <strong>90%</strong> 市場份額</li><li>2026 年供需缺口預估 <strong>10%+</strong></li><li>台玻、南亞塑膠的替代方案最早 2027 年才能上產能</li><li><strong>缺口</strong>：缺乏對日東紡實際產能與定價權的深入分析</li></ul><hr><h2 id="🔴-問題四-中國競爭者的真實進度難以驗證" tabindex="-1">🔴 問題四：中國競爭者的真實進度難以驗證 <a class="header-anchor" href="#🔴-問題四-中國競爭者的真實進度難以驗證" aria-label="Permalink to &quot;🔴 問題四：中國競爭者的真實進度難以驗證&quot;">​</a></h2><ul><li>京東方、Visionox、長電科技的進度多來自中國媒體報導</li><li><strong>缺乏第三方驗證</strong>，可能過度樂觀</li><li>例如長電科技「已成功整合玻璃核心基板至 1.6T 光模組」無法獨立查證</li></ul><hr><h2 id="🔴-問題五-市場規模預測差異過大" tabindex="-1">🔴 問題五：市場規模預測差異過大 <a class="header-anchor" href="#🔴-問題五-市場規模預測差異過大" aria-label="Permalink to &quot;🔴 問題五：市場規模預測差異過大&quot;">​</a></h2><table tabindex="0"><thead><tr><th>機構</th><th>2036 年預測</th></tr></thead><tbody><tr><td>QY Research</td><td>$821M（2032）</td></tr><tr><td>Mordor Intelligence</td><td>$9,010M（2031）</td></tr><tr><td>IDTechEx</td><td>$4,400M（2036）</td></tr></tbody></table><ul><li>同一技術，不同機構預測差距 <strong>5 倍以上</strong></li><li><strong>缺口</strong>：未分析各機構的假設差異與可信度</li></ul><hr><h2 id="🔴-問題六-良率瓶頸是最核心風險-但無解方" tabindex="-1">🔴 問題六：良率瓶頸是最核心風險，但無解方 <a class="header-anchor" href="#🔴-問題六-良率瓶頸是最核心風險-但無解方" aria-label="Permalink to &quot;🔴 問題六：良率瓶頸是最核心風險，但無解方&quot;">​</a></h2><ul><li>玻璃基板目前良率 <strong>75-85%</strong>，有機基板 &gt;95%</li><li>成本高出 <strong>30-50%</strong></li><li>多數報告提到「持續改進」，但<strong>無具體改善路徑與時程</strong></li></ul><hr><h2 id="🔴-問題七-散熱問題被低估" tabindex="-1">🔴 問題七：散熱問題被低估 <a class="header-anchor" href="#🔴-問題七-散熱問題被低估" aria-label="Permalink to &quot;🔴 問題七：散熱問題被低估&quot;">​</a></h2><ul><li>玻璃導熱率僅 <strong>1-2 W/mK</strong>，矽是 150、陶瓷是 170-200</li><li><blockquote><p>50W/封裝散熱困難，但 AI 晶片功率持續攀升</p></blockquote></li><li><strong>缺口</strong>：缺乏具體散熱解決方案的成本效益分析</li></ul><hr><h2 id="🔴-問題八-標準化完全缺失" tabindex="-1">🔴 問題八：標準化完全缺失 <a class="header-anchor" href="#🔴-問題八-標準化完全缺失" aria-label="Permalink to &quot;🔴 問題八：標準化完全缺失&quot;">​</a></h2><ul><li>面板尺寸不統一（620×750mm、700×700mm 等）</li><li>缺乏統一測試規範與 EDA 工具支援</li><li><strong>缺口</strong>：未追蹤 IEEE 或 JEDEC 是否有標準化進展</li></ul><hr><h2 id="📋-總結-需要補充的研究" tabindex="-1">📋 總結：需要補充的研究 <a class="header-anchor" href="#📋-總結-需要補充的研究" aria-label="Permalink to &quot;📋 總結：需要補充的研究&quot;">​</a></h2><ol><li><strong>日東紡深度分析</strong> — 產能、定價權、台廠替代方案時程</li><li><strong>中國競爭者第三方驗證</strong> — 尋找非中國來源的進度確認</li><li><strong>良率改善路徑</strong> — 各廠具體技術方案與時程</li><li><strong>散熱解決方案成本分析</strong> — 嵌入式散熱孔、液冷的實際成本</li><li><strong>標準化進展追蹤</strong> — IEEE/JEDEC 是否有新標準發布</li></ol><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li>玻璃基板三份既有報告（產業總覽、台股供應鏈、技術路線圖）</li><li>各研究機構公開報告（Yole, QY Research, IDTechEx 等）</li><li>Digitimes、TechNews、Tom&#39;s Hardware 等產業媒體</li></ol>',33)])])}const _=l(o,[["render",e]]);export{c as __pageData,_ as default};
